import type { ProjectBoardColumn } from '@motivation/shared';
import stylesText from './project-scrumboard.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { formatProjectStatusLabel, projectStatusClass } from '../project-shared.js';
import { ProjectsService } from '../../../../services/projects.service.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';

const template = document.createElement('template');
template.innerHTML = `
<div class="state" id="loading">Loading scrumboard…</div>
<div class="state" id="error" hidden></div>
<div class="board-columns" id="columns" hidden></div>
<template id="column-template">
    <details class="board-column">
        <summary class="column-summary">
            <span class="column-title"></span>
            <span class="column-hint">Tap for stories</span>
        </summary>
        <ul class="board-list"></ul>
    </details>
</template>
<template id="item-template">
    <li class="board-entry">
        <details class="board-item">
            <summary class="item-summary">
                <span class="item-text">
                    <span class="item-id"></span>
                    <span class="item-title"></span>
                </span>
                <span class="status"></span>
            </summary>
            <p class="item-meta"></p>
        </details>
    </li>
</template>
`;

export class ProjectScrumboard extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private columnsEl!: HTMLElement;
    private columnTemplateEl!: HTMLTemplateElement;
    private itemTemplateEl!: HTMLTemplateElement;
    private loadSequence = 0;
    private readonly log = createComponentLogger('project-scrumboard');

    static get observedAttributes(): string[] {
        return ['project-id'];
    }

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.columnsEl = this.shadowRootRef.getElementById('columns') as HTMLElement;
        this.columnTemplateEl = this.shadowRootRef.getElementById('column-template') as HTMLTemplateElement;
        this.itemTemplateEl = this.shadowRootRef.getElementById('item-template') as HTMLTemplateElement;
        void this.loadData();
    }

    attributeChangedCallback(): void {
        if (!this.isConnected || !this.loadingEl) return;
        void this.loadData();
    }

    private async loadData(): Promise<void> {
        const projectId = this.getAttribute('project-id');
        if (projectId !== 'motivation' || !this.loadingEl) return;

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.columnsEl.hidden = true;

        try {
            const dashboard = await ProjectsService.fetchMotivationDashboard();
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.renderColumns(dashboard.scrumboard.columns);
        } catch (error) {
            this.log.error('Failed to load scrumboard', error);
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = 'Failed to load scrumboard.';
        }
    }

    private renderColumns(columns: ProjectBoardColumn[]): void {
        this.columnsEl.replaceChildren(...columns.map((column) => {
            const fragment = this.columnTemplateEl.content.cloneNode(true) as DocumentFragment;
            const columnEl = fragment.querySelector('.board-column') as HTMLElement;
            const title = fragment.querySelector('.column-title') as HTMLElement;
            const list = fragment.querySelector('.board-list') as HTMLElement;
            title.textContent = `${column.title} (${column.items.length})`;
            if (column.id === 'active-sprint' || column.id === 'high-priority') {
                (columnEl as HTMLDetailsElement).open = true;
            }

            if (column.items.length === 0) {
                const empty = document.createElement('li');
                empty.className = 'board-item board-item--empty';
                empty.textContent = 'No stories in this lane.';
                list.appendChild(empty);
            } else {
                for (const item of column.items) {
                    const fragment = this.itemTemplateEl.content.cloneNode(true) as DocumentFragment;
                    (fragment.querySelector('.item-id') as HTMLElement).textContent =
                        item.points == null ? `Story ${item.id}` : `Story ${item.id} · ${item.points} pts`;

                    const status = fragment.querySelector('.status') as HTMLElement;
                    status.className = projectStatusClass(item.status);
                    status.textContent = formatProjectStatusLabel(item.status);

                    (fragment.querySelector('.item-title') as HTMLElement).textContent = item.title;
                    (fragment.querySelector('.item-meta') as HTMLElement).textContent =
                        item.points == null ? 'No estimate recorded for this item.' : `${item.points} story points`;
                    list.appendChild(fragment);
                }
            }

            return columnEl;
        }));
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.columnsEl.hidden = false;
    }
}

if (!customElements.get('project-scrumboard')) {
    customElements.define('project-scrumboard', ProjectScrumboard);
}
